// Параметры
const CHUNK_SIZE = 20;

// Функция разделения массива на части
function splitArray(array, chunkSize) {
  const chunks = [];
  for (let i = 0; i < array.length; i += chunkSize) {
    chunks.push(array.slice(i, i + chunkSize));
  }
  return chunks;
}

// Получаем JSON строку
let jsonString = $input.first().json.candidates[0].content.parts[0].text;

// Парсим JSON
let dataArray;
try {
  // ИСПРАВЛЕНИЕ: Убираем markdown форматирование (```json и ```)
  if (typeof jsonString === 'string') {
    // Удаляем ```json в начале и ``` в конце
    jsonString = jsonString.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  }

  dataArray = JSON.parse(jsonString);

  // Если это объект с полем "assets", извлекаем массив
  if (dataArray.assets && Array.isArray(dataArray.assets)) {
    dataArray = dataArray.assets;
  }
} catch (error) {
  throw new Error('Ошибка парсинга JSON: ' + error.message);
}

// Проверяем, что это массив
if (!Array.isArray(dataArray)) {
  throw new Error('Данные должны быть массивом');
}

// Разделяем на части
const chunks = splitArray(dataArray, CHUNK_SIZE);

// Формируем выходные данные для n8n
const output = chunks.map((chunk, index) => ({
  json: {
    data: chunk
  }
}));

return output;
